import{_ as a,o as e,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"At-Bat Logger","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/at-bat-logger.md","filePath":"scoring-games/at-bat-logger.md"}'),i={name:"scoring-games/at-bat-logger.md"};function n(l,t,h,d,s,g){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="at-bat-logger" tabindex="-1">At-Bat Logger <a class="header-anchor" href="#at-bat-logger" aria-label="Permalink to &quot;At-Bat Logger&quot;">​</a></h1><p>The At-Bat Logger records hitting results for each batter. Data from the At-Bat Logger drives batting average, on-base percentage, slugging, and all hitting analytics.</p><h2 id="logging-an-at-bat" tabindex="-1">Logging an At-Bat <a class="header-anchor" href="#logging-an-at-bat" aria-label="Permalink to &quot;Logging an At-Bat&quot;">​</a></h2><ol><li>Select the batter from the player selector</li><li>Select the <strong>contact type</strong> — how the ball was hit</li><li>Select the <strong>result</strong> — what happened</li><li>Tap the <strong>spray chart</strong> to indicate where the ball went</li><li>Optionally toggle <strong>Hard Hit</strong> if the ball was hit with authority</li><li>The record saves automatically</li></ol><h2 id="contact-types" tabindex="-1">Contact Types <a class="header-anchor" href="#contact-types" aria-label="Permalink to &quot;Contact Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Ground Ball</td><td>Ball hit on the ground</td></tr><tr><td>Line Drive</td><td>Ball hit on a line, low trajectory</td></tr><tr><td>Fly Ball</td><td>Ball hit in the air, high trajectory</td></tr></tbody></table><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Result</th><th>Description</th></tr></thead><tbody><tr><td>Hit</td><td>Single, double, or triple</td></tr><tr><td>HR</td><td>Home run</td></tr><tr><td>Out</td><td>Any out — groundout, flyout, lineout</td></tr><tr><td>K Swing</td><td>Strikeout swinging</td></tr><tr><td>K Look</td><td>Strikeout looking</td></tr><tr><td>BB</td><td>Walk (base on balls)</td></tr><tr><td>HBP</td><td>Hit by pitch</td></tr><tr><td>ER</td><td>Reached on error</td></tr><tr><td>FC</td><td>Fielder&#39;s choice</td></tr></tbody></table><h2 id="spray-chart" tabindex="-1">Spray Chart <a class="header-anchor" href="#spray-chart" aria-label="Permalink to &quot;Spray Chart&quot;">​</a></h2><p>The spray chart shows the field from above. Tap the zone where the ball was hit to record the hit location. This data drives the spray chart heat map in hitting analytics.</p><p>Spray zones include all outfield areas (Shallow LF, Deep LF, Left Center Gap, Center Field, Right Center Gap, Shallow RF, Deep RF) and infield positions (3B, SS, 2B, 1B, Pitcher/Catcher area).</p><h2 id="hard-hit-toggle" tabindex="-1">Hard Hit Toggle <a class="header-anchor" href="#hard-hit-toggle" aria-label="Permalink to &quot;Hard Hit Toggle&quot;">​</a></h2><p>The <strong>Hard Hit</strong> button above the spray chart toggles whether the ball was hit with significant force. Hard hit rate is tracked separately in hitting analytics and can be used to identify power hitters and contact quality.</p><h2 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h2><p>The arrow button in the top right navigates directly to the <strong>Baserunning Logger</strong> — useful after a hit when you need to immediately log baserunning events for the runner who just reached base.</p>',15)])])}const p=a(i,[["render",n]]);export{u as __pageData,p as default};
